package com.eventstreaming.model;

import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonProperty;
import java.io.Serializable;
import java.time.Instant;
import java.util.Map;
import java.util.UUID;

public class PlatformEvent implements Serializable {

    private static final long serialVersionUID = 1L;

    private final String eventId;
    private final String eventType;
    private final String source;
    private final Instant timestamp;
    private final Map<String, Object> payload;
    private final String correlationId;

    @JsonCreator
    public PlatformEvent(
            @JsonProperty("eventId") String eventId,
            @JsonProperty("eventType") String eventType,
            @JsonProperty("source") String source,
            @JsonProperty("timestamp") Instant timestamp,
            @JsonProperty("payload") Map<String, Object> payload,
            @JsonProperty("correlationId") String correlationId) {
        this.eventId = eventId != null ? eventId : UUID.randomUUID().toString();
        this.eventType = eventType;
        this.source = source;
        this.timestamp = timestamp != null ? timestamp : Instant.now();
        this.payload = payload;
        this.correlationId = correlationId != null ? correlationId : UUID.randomUUID().toString();
    }

    public static PlatformEvent create(String eventType, String source, Map<String, Object> payload) {
        return new PlatformEvent(null, eventType, source, null, payload, null);
    }

    public String getEventId() { return eventId; }
    public String getEventType() { return eventType; }
    public String getSource() { return source; }
    public Instant getTimestamp() { return timestamp; }
    public Map<String, Object> getPayload() { return payload; }
    public String getCorrelationId() { return correlationId; }

    @Override
    public String toString() {
        return "PlatformEvent{" +
                "eventId='" + eventId + '\'' +
                ", eventType='" + eventType + '\'' +
                ", source='" + source + '\'' +
                ", timestamp=" + timestamp +
                ", correlationId='" + correlationId + '\'' +
                '}';
    }
}

