package com.eventstreaming.config;

import org.apache.kafka.clients.CommonClientConfigs;
import org.apache.kafka.common.config.SaslConfigs;
import org.apache.kafka.common.config.SslConfigs;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Configuration;

import jakarta.annotation.PostConstruct;
import java.util.HashMap;
import java.util.Map;

@Configuration
public class KafkaSecurityConfig {

    private static final Logger logger = LoggerFactory.getLogger(KafkaSecurityConfig.class);

    @Value("${spring.kafka.properties.security.protocol:SASL_SSL}")
    private String securityProtocol;

    @Value("${spring.kafka.properties.sasl.mechanism:SCRAM-SHA-512}")
    private String saslMechanism;

    @Value("${KAFKA_USERNAME:#{null}}")
    private String kafkaUsername;

    @Value("${KAFKA_PASSWORD:#{null}}")
    private String kafkaPassword;

    @Value("${spring.kafka.properties.ssl.truststore.location:#{null}}")
    private String truststoreLocation;

    @Value("${spring.kafka.properties.ssl.truststore.password:#{null}}")
    private String truststorePassword;

    @PostConstruct
    public void validateSecurityConfiguration() {
        if (kafkaUsername == null || kafkaUsername.isBlank()) {
            logger.warn("KAFKA_USERNAME is not set. Ensure Kafka authentication is properly configured.");
        }
        if (kafkaPassword == null || kafkaPassword.isBlank()) {
            logger.warn("KAFKA_PASSWORD is not set. Ensure Kafka authentication is properly configured.");
        }
        if ("SASL_SSL".equals(securityProtocol) || "SSL".equals(securityProtocol)) {
            if (truststoreLocation == null || truststoreLocation.isBlank()) {
                logger.warn("SSL truststore location is not configured for protocol: {}", securityProtocol);
            }
        }
        logger.info("Kafka security protocol: {}, SASL mechanism: {}", securityProtocol, saslMechanism);
    }

    public Map<String, Object> buildSecurityProperties() {
        Map<String, Object> props = new HashMap<>();

        props.put(CommonClientConfigs.SECURITY_PROTOCOL_CONFIG, securityProtocol);

        if (securityProtocol.contains("SASL")) {
            props.put(SaslConfigs.SASL_MECHANISM, saslMechanism);

            if (kafkaUsername != null && kafkaPassword != null) {
                String jaasConfig = String.format(
                        "org.apache.kafka.common.security.scram.ScramLoginModule required " +
                                "username=\"%s\" password=\"%s\";",
                        kafkaUsername, kafkaPassword);
                props.put(SaslConfigs.SASL_JAAS_CONFIG, jaasConfig);
            }
        }

        if (securityProtocol.contains("SSL")) {
            if (truststoreLocation != null && !truststoreLocation.isBlank()) {
                props.put(SslConfigs.SSL_TRUSTSTORE_LOCATION_CONFIG, truststoreLocation);
            }
            if (truststorePassword != null && !truststorePassword.isBlank()) {
                props.put(SslConfigs.SSL_TRUSTSTORE_PASSWORD_CONFIG, truststorePassword);
            }
            props.put(SslConfigs.SSL_ENDPOINT_IDENTIFICATION_ALGORITHM_CONFIG, "https");
        }

        return props;
    }
}

