package com.eventstreaming.producer;

import com.eventstreaming.model.PlatformEvent;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.kafka.support.SendResult;
import org.springframework.messaging.Message;
import org.springframework.messaging.support.MessageBuilder;
import org.springframework.stereotype.Service;

import java.util.concurrent.CompletableFuture;

@Service
public class EventProducer {

    private static final Logger logger = LoggerFactory.getLogger(EventProducer.class);

    private final KafkaTemplate<String, PlatformEvent> kafkaTemplate;

    @Value("${app.kafka.topics.events:platform-events}")
    private String eventsTopic;

    @Value("${app.kafka.topics.notifications:platform-notifications}")
    private String notificationsTopic;

    public EventProducer(KafkaTemplate<String, PlatformEvent> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public CompletableFuture<SendResult<String, PlatformEvent>> publishEvent(PlatformEvent event) {
        return publishToTopic(eventsTopic, event);
    }

    public CompletableFuture<SendResult<String, PlatformEvent>> publishNotification(PlatformEvent event) {
        return publishToTopic(notificationsTopic, event);
    }

    public CompletableFuture<SendResult<String, PlatformEvent>> publishToTopic(String topic, PlatformEvent event) {
        logger.info("Publishing event to topic [{}]: eventId={}, eventType={}, correlationId={}",
                topic, event.getEventId(), event.getEventType(), event.getCorrelationId());

        Message<PlatformEvent> message = MessageBuilder
                .withPayload(event)
                .setHeader(KafkaHeaders.TOPIC, topic)
                .setHeader(KafkaHeaders.KEY, event.getEventId())
                .setHeader("X-Correlation-Id", event.getCorrelationId())
                .setHeader("X-Event-Type", event.getEventType())
                .setHeader("X-Source", event.getSource())
                .build();

        CompletableFuture<SendResult<String, PlatformEvent>> future = kafkaTemplate.send(message);

        future.whenComplete((result, ex) -> {
            if (ex != null) {
                logger.error("Failed to publish event [{}] to topic [{}]: {}",
                        event.getEventId(), topic, ex.getMessage(), ex);
            } else {
                logger.info("Successfully published event [{}] to topic [{}], partition={}, offset={}",
                        event.getEventId(), topic,
                        result.getRecordMetadata().partition(),
                        result.getRecordMetadata().offset());
            }
        });

        return future;
    }
}

