package com.eventstreaming.consumer;

import com.eventstreaming.model.PlatformEvent;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.handler.annotation.Header;
import org.springframework.messaging.handler.annotation.Payload;
import org.springframework.stereotype.Service;

@Service
public class EventConsumer {

    private static final Logger logger = LoggerFactory.getLogger(EventConsumer.class);

    @KafkaListener(
            topics = "${app.kafka.topics.events:platform-events}",
            groupId = "${spring.kafka.consumer.group-id:event-streaming-group}",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeEvent(
            @Payload PlatformEvent event,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
            @Header(KafkaHeaders.OFFSET) long offset,
            @Header(value = "X-Correlation-Id", required = false) String correlationId) {

        logger.info("Received event from topic [{}], partition={}, offset={}: eventId={}, eventType={}, correlationId={}",
                topic, partition, offset, event.getEventId(), event.getEventType(), correlationId);

        try {
            processEvent(event);
            logger.info("Successfully processed event: {}", event.getEventId());
        } catch (Exception e) {
            logger.error("Error processing event [{}]: {}", event.getEventId(), e.getMessage(), e);
            throw e; // Re-throw to trigger error handler / retry
        }
    }

    @KafkaListener(
            topics = "${app.kafka.topics.notifications:platform-notifications}",
            groupId = "${spring.kafka.consumer.group-id:event-streaming-group}-notifications",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeNotification(
            @Payload PlatformEvent event,
            @Header(KafkaHeaders.RECEIVED_TOPIC) String topic,
            @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
            @Header(KafkaHeaders.OFFSET) long offset) {

        logger.info("Received notification from topic [{}], partition={}, offset={}: eventId={}, eventType={}",
                topic, partition, offset, event.getEventId(), event.getEventType());

        try {
            processNotification(event);
            logger.info("Successfully processed notification: {}", event.getEventId());
        } catch (Exception e) {
            logger.error("Error processing notification [{}]: {}", event.getEventId(), e.getMessage(), e);
            throw e;
        }
    }

    @KafkaListener(
            topics = "${app.kafka.topics.dead-letter:platform-events-dlt}",
            groupId = "${spring.kafka.consumer.group-id:event-streaming-group}-dlt",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void consumeDeadLetter(ConsumerRecord<String, PlatformEvent> record) {
        logger.warn("Received dead letter message: topic={}, partition={}, offset={}, key={}, value={}",
                record.topic(), record.partition(), record.offset(), record.key(), record.value());

        // Handle dead letter messages - log, alert, store for manual review
    }

    private void processEvent(PlatformEvent event) {
        logger.debug("Processing event: type={}, source={}, payload={}",
                event.getEventType(), event.getSource(), event.getPayload());

        switch (event.getEventType()) {
            case "USER_CREATED":
                handleUserCreated(event);
                break;
            case "ORDER_PLACED":
                handleOrderPlaced(event);
                break;
            case "PAYMENT_PROCESSED":
                handlePaymentProcessed(event);
                break;
            default:
                logger.info("Unhandled event type: {}", event.getEventType());
        }
    }

    private void processNotification(PlatformEvent event) {
        logger.debug("Processing notification: type={}, source={}", event.getEventType(), event.getSource());
    }

    private void handleUserCreated(PlatformEvent event) {
        logger.info("Handling USER_CREATED event: {}", event.getEventId());
    }

    private void handleOrderPlaced(PlatformEvent event) {
        logger.info("Handling ORDER_PLACED event: {}", event.getEventId());
    }

    private void handlePaymentProcessed(PlatformEvent event) {
        logger.info("Handling PAYMENT_PROCESSED event: {}", event.getEventId());
    }
}

