package com.eventstreaming.controller;

import com.eventstreaming.model.PlatformEvent;
import com.eventstreaming.producer.EventProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.TimeoutException;

@RestController
@RequestMapping("/api/v1/events")
public class EventController {

    private static final Logger logger = LoggerFactory.getLogger(EventController.class);

    private final EventProducer eventProducer;

    public EventController(EventProducer eventProducer) {
        this.eventProducer = eventProducer;
    }

    @PostMapping
    public ResponseEntity<Map<String, String>> publishEvent(@RequestBody EventRequest request) {
        try {
            PlatformEvent event = PlatformEvent.create(
                    request.eventType(),
                    request.source(),
                    request.payload()
            );

            eventProducer.publishEvent(event)
                    .get(10, TimeUnit.SECONDS);

            return ResponseEntity.status(HttpStatus.ACCEPTED)
                    .body(Map.of(
                            "status", "accepted",
                            "eventId", event.getEventId(),
                            "correlationId", event.getCorrelationId()
                    ));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            logger.error("Interrupted while publishing event", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("status", "error", "message", "Publishing interrupted"));
        } catch (ExecutionException | TimeoutException e) {
            logger.error("Failed to publish event", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("status", "error", "message", "Failed to publish event"));
        }
    }

    @PostMapping("/notifications")
    public ResponseEntity<Map<String, String>> publishNotification(@RequestBody EventRequest request) {
        try {
            PlatformEvent event = PlatformEvent.create(
                    request.eventType(),
                    request.source(),
                    request.payload()
            );

            eventProducer.publishNotification(event)
                    .get(10, TimeUnit.SECONDS);

            return ResponseEntity.status(HttpStatus.ACCEPTED)
                    .body(Map.of(
                            "status", "accepted",
                            "eventId", event.getEventId(),
                            "correlationId", event.getCorrelationId()
                    ));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            logger.error("Interrupted while publishing notification", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("status", "error", "message", "Publishing interrupted"));
        } catch (ExecutionException | TimeoutException e) {
            logger.error("Failed to publish notification", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Map.of("status", "error", "message", "Failed to publish notification"));
        }
    }

    public record EventRequest(
            String eventType,
            String source,
            Map<String, Object> payload
    ) {}
}

