package com.eventstreaming.health;

import org.apache.kafka.clients.admin.AdminClient;
import org.apache.kafka.clients.admin.AdminClientConfig;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.actuate.health.Health;
import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.stereotype.Component;

import com.eventstreaming.config.KafkaSecurityConfig;

import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.TimeUnit;

@Component
public class KafkaHealthIndicator implements HealthIndicator {

    private static final Logger logger = LoggerFactory.getLogger(KafkaHealthIndicator.class);

    @Value("${spring.kafka.bootstrap-servers}")
    private String bootstrapServers;

    @Autowired
    private KafkaSecurityConfig kafkaSecurityConfig;

    @Override
    public Health health() {
        try {
            Map<String, Object> config = new HashMap<>();
            config.put(AdminClientConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
            config.put(AdminClientConfig.REQUEST_TIMEOUT_MS_CONFIG, 5000);
            config.put(AdminClientConfig.DEFAULT_API_TIMEOUT_MS_CONFIG, 5000);
            config.putAll(kafkaSecurityConfig.buildSecurityProperties());

            try (AdminClient adminClient = AdminClient.create(config)) {
                var nodes = adminClient.describeCluster().nodes().get(5, TimeUnit.SECONDS);
                return Health.up()
                        .withDetail("bootstrapServers", bootstrapServers)
                        .withDetail("nodes", nodes.size())
                        .build();
            }
        } catch (Exception e) {
            logger.warn("Kafka health check failed: {}", e.getMessage());
            return Health.down()
                    .withDetail("bootstrapServers", bootstrapServers)
                    .withException(e)
                    .build();
        }
    }
}